import{_ as d,C as s,o as i,c as l,j as t,a as e,b as p,w as n,E as o,a6 as u,a5 as m}from"./chunks/framework.CiX2n_L2.js";const y=JSON.parse('{"title":"Tips Agar Pendaftaran Cepat Selesai","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ppdgs/extra/tips-cepat.md","filePath":"ppdgs/extra/tips-cepat.md","lastUpdated":null}'),k={name:"ppdgs/extra/tips-cepat.md"};function b(h,a,g,c,f,S){const r=s("Mermaid");return i(),l("div",null,[a[1]||(a[1]=t("h1",{id:"tips-agar-pendaftaran-cepat-selesai",tabindex:"-1"},[e("Tips Agar Pendaftaran Cepat Selesai "),t("a",{class:"header-anchor",href:"#tips-agar-pendaftaran-cepat-selesai","aria-label":'Permalink to "Tips Agar Pendaftaran Cepat Selesai"'},"​")],-1)),a[2]||(a[2]=t("p",null,"Ingin proses pendaftaran PPDGS berjalan lancar dan cepat? Ikuti tips-tips berikut.",-1)),(i(),p(u,null,{default:n(()=>[o(r,{id:"mermaid-6",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5BPersiapan%20Matang%5D%20--%3E%20B%5BIsi%20Data%20Tepat%5D%0A%20%20%20%20B%20--%3E%20C%5BForm%20Lengkap%5D%0A%20%20%20%20C%20--%3E%20D%5BBayar%20Segera%5D%0A%20%20%20%20D%20--%3E%20E%5BVerifikasi%20Cepat%5D%0A%20%20%20%20E%20--%3E%20F%5BSelesai%5D%0A%20%20%20%20A%20-.-%3E%7CTips%201%7C%20A1%5BSiapkan%20Dokumen%5D%0A%20%20%20%20B%20-.-%3E%7CTips%202%7C%20B1%5BIsi%20dengan%20Teliti%5D%0A%20%20%20%20C%20-.-%3E%7CTips%203%7C%20C1%5BIsi%20Form%20Berurutan%5D%0A%20%20%20%20D%20-.-%3E%7CTips%204%7C%20D1%5BTransfer%20Segera%5D%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=m('<h2 id="_1-siapkan-semua-dokumen-sebelum-mendaftar" tabindex="-1">1. Siapkan Semua Dokumen Sebelum Mendaftar <a class="header-anchor" href="#_1-siapkan-semua-dokumen-sebelum-mendaftar" aria-label="Permalink to &quot;1. Siapkan Semua Dokumen Sebelum Mendaftar&quot;">​</a></h2><div class="info-card tip"><p>Ini adalah tips paling penting! Jangan mulai mendaftar jika dokumen belum siap.</p></div><p><strong>Lakukan sebelum mulai:</strong></p><ul><li>[x] Siapkan foto terbaru (formal, latar merah)</li><li>[x] Scan ijazah S1 dan ijazah profesi (legalisir basah)</li><li>[x] Siapkan sertifikat non formal, prestasi, dan karya tulis</li><li>[x] Konversi semua dokumen ke format JPG</li><li>[x] Pastikan ukuran file di bawah 1 MB dan resolusi maksimal 2500 x 1600 px</li><li>[x] Simpan di folder khusus di komputer/HP</li></ul><h2 id="_2-gunakan-laptop-atau-pc" tabindex="-1">2. Gunakan Laptop atau PC <a class="header-anchor" href="#_2-gunakan-laptop-atau-pc" aria-label="Permalink to &quot;2. Gunakan Laptop atau PC&quot;">​</a></h2><div class="info-card warning"><p>Meskipun bisa menggunakan HP, proses pengisian form dan upload dokumen akan lebih mudah di laptop atau PC.</p></div><p><strong>Keuntungan menggunakan laptop:</strong></p><ul><li>Layar lebih besar untuk melihat form bertab</li><li>Keyboard lebih nyaman untuk mengetik deskripsi diri</li><li>Koneksi internet lebih stabil (LAN)</li><li>Mempermudah manajemen file</li></ul><h2 id="_3-siapkan-koneksi-internet-yang-stabil" tabindex="-1">3. Siapkan Koneksi Internet yang Stabil <a class="header-anchor" href="#_3-siapkan-koneksi-internet-yang-stabil" aria-label="Permalink to &quot;3. Siapkan Koneksi Internet yang Stabil&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aktivitas</th><th>Kecepatan Minimal</th><th>Saran</th></tr></thead><tbody><tr><td>Isi form</td><td>1 Mbps</td><td>Cukup</td></tr><tr><td>Upload dokumen (via tab)</td><td>5 Mbps</td><td>Gunakan WiFi</td></tr><tr><td>Upload banyak tab</td><td>10 Mbps</td><td>Hindari jam sibuk</td></tr></tbody></table><h2 id="_4-isi-data-dengan-teliti" tabindex="-1">4. Isi Data dengan Teliti <a class="header-anchor" href="#_4-isi-data-dengan-teliti" aria-label="Permalink to &quot;4. Isi Data dengan Teliti&quot;">​</a></h2><div class="info-card danger"><p>Kesalahan data dapat memperlambat proses verifikasi. Isi data dengan cermat!</p></div><p><strong>Perhatikan:</strong></p><ul><li>Nama sesuai KTP (tanpa gelar)</li><li>Tanggal lahir format DD/MM/YYYY</li><li>Nomor HP diawali 62</li><li>Alamat lengkap</li><li>Isi semua field yang bertanda wajib di setiap tab</li></ul><h2 id="_5-siapkan-jawaban-deskripsi-diri" tabindex="-1">5. Siapkan Jawaban Deskripsi Diri <a class="header-anchor" href="#_5-siapkan-jawaban-deskripsi-diri" aria-label="Permalink to &quot;5. Siapkan Jawaban Deskripsi Diri&quot;">​</a></h2><div class="info-card warning"><p>Terdapat 16 pertanyaan Deskripsi Diri yang harus diisi menggunakan <strong>Summernote</strong> (rich text editor). Persiapkan jawaban terlebih dahulu agar tidak perlu mengetik panjang saat mengisi formulir.</p></div><p><strong>Tips mengisi Deskripsi Diri:</strong></p><ul><li>Siapkan draf jawaban di Word/Google Docs sebelum mendaftar</li><li>Jawab setiap sub-pertanyaan secara lengkap</li><li>Gunakan format paragraf yang rapi (maksimal 5000 karakter per pertanyaan)</li><li>Jangan copy-paste jawaban yang sama untuk pertanyaan berbeda</li><li>Periksa ejaan sebelum menyimpan</li></ul><h2 id="_6-isi-form-secara-berurutan" tabindex="-1">6. Isi Form Secara Berurutan <a class="header-anchor" href="#_6-isi-form-secara-berurutan" aria-label="Permalink to &quot;6. Isi Form Secara Berurutan&quot;">​</a></h2><p>Isi setiap tab dari kiri ke kanan secara berurutan. Upload dokumen langsung saat berada di tab yang sesuai. Jangan melompat-lompat agar tidak ada field yang terlewat.</p><h2 id="_7-lakukan-pembayaran-segera" tabindex="-1">7. Lakukan Pembayaran Segera <a class="header-anchor" href="#_7-lakukan-pembayaran-segera" aria-label="Permalink to &quot;7. Lakukan Pembayaran Segera&quot;">​</a></h2><p>Setelah semua tab terisi lengkap, segera lakukan pembayaran dan upload bukti pembayaran di menu Pembayaran. Jangan menunggu mendekati batas waktu.</p><h2 id="_8-pantau-status-secara-rutin" tabindex="-1">8. Pantau Status Secara Rutin <a class="header-anchor" href="#_8-pantau-status-secara-rutin" aria-label="Permalink to &quot;8. Pantau Status Secara Rutin&quot;">​</a></h2><p>Periksa dashboard setiap hari untuk:</p><ul><li>Memastikan tidak ada dokumen yang ditolak</li><li>Melihat update status terbaru</li><li>Merespon cepat jika ada permintaan revisi</li></ul><h2 id="_9-catat-nomor-registrasi" tabindex="-1">9. Catat Nomor Registrasi <a class="header-anchor" href="#_9-catat-nomor-registrasi" aria-label="Permalink to &quot;9. Catat Nomor Registrasi&quot;">​</a></h2><p>Segera setelah mendaftar, catat nomor registrasi Anda. Nomor ini akan diperlukan untuk:</p><ul><li>Komunikasi dengan admin</li><li>Pembayaran</li><li>Melacak status pendaftaran</li></ul><h2 id="timeline-ideal" tabindex="-1">Timeline Ideal <a class="header-anchor" href="#timeline-ideal" aria-label="Permalink to &quot;Timeline Ideal&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Hari</th><th>Aktivitas</th><th>Durasi</th></tr></thead><tbody><tr><td>Hari 1</td><td>Siapkan dokumen dan draf jawaban deskripsi diri</td><td>2-3 jam</td></tr><tr><td>Hari 2</td><td>Registrasi akun &amp; isi biodata</td><td>30 menit</td></tr><tr><td>Hari 2</td><td>Isi tab Pendidikan Kedokteran (ijazah + deskripsi)</td><td>30 menit</td></tr><tr><td>Hari 2</td><td>Isi tab Pendidikan Non Formal</td><td>15 menit</td></tr><tr><td>Hari 2</td><td>Isi tab Karya Tulis</td><td>15 menit</td></tr><tr><td>Hari 2</td><td>Isi tab Prestasi dan Penghargaan</td><td>15 menit</td></tr><tr><td>Hari 2</td><td>Upload bukti pembayaran</td><td>15 menit</td></tr><tr><td>Hari 3-5</td><td>Verifikasi admin</td><td>1-3 hari</td></tr><tr><td>Hari 5+</td><td>Selesai</td><td>-</td></tr></tbody></table>',30))])}const _=d(k,[["render",b]]);export{y as __pageData,_ as default};
